        <div class="cart-preview" data-cart-preview>
          <?php if ( empty( $cart_items ) ) : ?>
            <p class="cart-preview-empty">Your cart is empty.</p>
          <?php else : ?>
            <table class="cart-preview-table">
              <thead>
                <tr>
                  <th class="cpt-img"></th>
