              <tbody>
                <?php foreach ( $cart_items as $item ) :
                  $product  = $item['data'];
                  $img_id   = $product->get_image_id();
                  $img_url  = $img_id ? wp_get_attachment_image_url( $img_id, 'thumbnail' ) : wc_placeholder_img_src();
                ?>
                <tr class="cpt-row">
