            <div class="cart-preview-footer">
              <span class="cart-preview-total">Total: <?php echo WC()->cart->get_cart_total(); ?></span>
              <a href="<?php echo esc_url( wc_get_cart_url() ); ?>" class="btn-primary cart-preview-btn">View Cart</a>
